// Hesablama operatorları
let eggs = 3;
let people = 2;
let totalEggs = eggs * people; // Vurma
console.log(totalEggs); // nəticə: 6

let budget = 10;
budget += 5; // Toplama və təyinat
console.log(budget); // nəticə: 15

let counter = 1;
counter++; // Artırma
console.log(counter); // nəticə: 2

// Müqayisə operatorları
let temperature = 15;
if (temperature < 20) {
  console.log("İsti çay iç!");
} // nəticə: İsti çay iç!

console.log(5 === "5"); // nəticə: false (tip fərqlidir)
console.log(5 == "5"); // nəticə: true (dəyər eynidir)

// Məntiqi operatorlar
let hasTea = true;
let hasToast = false;
if (hasTea && !hasToast) {
  console.log("Yalnız çay içəcəm!");
} // nəticə: Yalnız çay içəcəm!

if (hasTea || hasToast) {
  console.log("Nəsə yeyib-içəcəm!");
} // nəticə: Nəsə yeyib-içəcəm!

// Təyinat operatorları
let budget = 10;
budget += 5; // budget = budget + 5
console.log(budget); // nəticə: 15

let quantity = 4;
quantity *= 2; // quantity = quantity * 2
console.log(quantity); // nəticə: 8

// Digər operatorlar
let greeting = "Salam, " + "Aysel"; // String birləşdirmə
console.log(greeting); // nəticə: Salam, Aysel

let age = 20;
let message = age >= 18 ? "Böyüksən!" : "Kiçiksən!";
console.log(message); // nəticə: Böyüksən!

console.log(typeof age); // nəticə: number

