// Arithmetic operators
let eggs = 3;
let people = 2;
let totalEggs = eggs * people; // Multiplication
console.log(totalEggs); // Output: 6

let budget = 10;
budget += 5; // Addition and assignment
console.log(budget); // Output: 15

let counter = 1;
counter++; // Increment
console.log(counter); // Output: 2

// Comparison operators
let temperature = 15;
if (temperature < 20) {
  console.log("Drink hot tea!");
} // Output: Drink hot tea!

console.log(5 === "5"); // Output: false (different types)
console.log(5 == "5"); // Output: true (same value)

// Logical operators
let hasTea = true;
let hasToast = false;
if (hasTea && !hasToast) {
  console.log("I’ll just have tea!");
} // Output: I’ll just have tea!

if (hasTea || hasToast) {
  console.log("I’ll eat or drink something!");
} // Output: I’ll eat or drink something!

// Assignment operators
let budget = 10;
budget += 5; // budget = budget + 5
console.log(budget); // Output: 15

let quantity = 4;
quantity *= 2; // quantity = quantity * 2
console.log(quantity); // Output: 8

// Other operators
let greeting = "Hello, " + "Aysel"; // String concatenation
console.log(greeting); // Output: Hello, Aysel

let age = 20;
let message = age >= 18 ? "You’re an adult!" : "You’re a minor!";
console.log(message); // Output: You’re an adult!

console.log(typeof age); // Output: number

