// Арифметические операторы
let eggs = 3;
let people = 2;
let totalEggs = eggs * people; // Умножение
console.log(totalEggs); // Вывод: 6

let budget = 10;
budget += 5; // Сложение и присваивание
console.log(budget); // Вывод: 15

let counter = 1;
counter++; // Инкремент
console.log(counter); // Вывод: 2

// Операторы сравнения
let temperature = 15;
if (temperature < 20) {
  console.log("Пей горячий чай!");
} // Вывод: Пей горячий чай!

console.log(5 === "5"); // Вывод: false (разные типы)
console.log(5 == "5"); // Вывод: true (одинаковое значение)

// Логические операторы
let hasTea = true;
let hasToast = false;
if (hasTea && !hasToast) {
  console.log("Я выпью только чай!");
} // Вывод: Я выпью только чай!

if (hasTea || hasToast) {
  console.log("Я поем или попью что-нибудь!");
} // Вывод: Я поем или попью что-нибудь!

// Операторы присваивания
let budget = 10;
budget += 5; // budget = budget + 5
console.log(budget); // Вывод: 15

let quantity = 4;
quantity *= 2; // quantity = quantity * 2
console.log(quantity); // Вывод: 8

// Другие операторы
let greeting = "Привет, " + "Айсель"; // Конкатенация строк
console.log(greeting); // Вывод: Привет, Айсель

let age = 20;
let message = age >= 18 ? "Ты взрослый!" : "Ты несовершеннолетний!";
console.log(message); // Вывод: Ты взрослый!

console.log(typeof age); // Вывод: number

